sql:
SELECT sub_region_name
FROM sub_regions
WHERE sub_region_id = 0;

SELECT region_id, COUNT(sub_region_id) AS sub_region_count
FROM sub_regions
GROUP BY region_id;

SELECT COUNT(*) AS migration_trend_count
FROM migration_trends
WHERE sub_region_id = 1;

external_knowledge:
- 'Both Sexes' means the category that includes both males and females; 
- '2010-2015' and '2015-2020' are the year ranges in which the average migration and refugee rates are calculated; 
- 'past decade' refers to the time period between '2010-2015' and '2015-2020'.

sql:
SELECT sub_region_name, description 
FROM sub_regions 
LIMIT 10;

SELECT sub_region_id, annual_rate_of_change
FROM migration_rates
WHERE year_range_id = (SELECT year_range_id FROM year_ranges WHERE year_range_name = '1995-2000');
